import React, { useEffect, useState } from "react";
import { useParams, Link } from "react-router-dom";
import Navbar from "../components/Navbar";
import { getFieldById } from "../services/api";

function FieldDetail() {
  const { id } = useParams();
  const [field, setField] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  useEffect(() => {
    const fetchField = async () => {
      try {
        const data = await getFieldById(id);
        setField(data);
      } catch (err) {
        setError(err.message);
      } finally {
        setLoading(false);
      }
    };

    fetchField();
  }, [id]);

  return (
    <div>
      <Navbar />

      <div style={{ padding: "30px" }}>
        {loading && <p>Đang tải chi tiết sân...</p>}
        {error && <p style={{ color: "red" }}>{error}</p>}

        {field && (
          <div>
            <h1>{field.name}</h1>
            <p>
              <strong>Giá:</strong> {field.price} VNĐ/giờ
            </p>
            <p>
              <strong>Trạng thái:</strong> {field.status}
            </p>

            <Link to={`/booking/${field.id}`}>
              <button>Đặt sân ngay</button>
            </Link>
          </div>
        )}
      </div>
    </div>
  );
}

export default FieldDetail;
